sql:
SELECT transaction_id, transaction_date
FROM financial_transactions
WHERE fiscal_year = 2020 AND entity_id = 100;

SELECT entity_id, entity_name
FROM county_entities
ORDER BY entity_id;

SELECT SUM(retirement_of_long_term_debt_operating_expenditures) AS Total_Retirement
FROM financial_transactions
WHERE fiscal_year = 2022;

SELECT entity_name
FROM county_entities
WHERE entity_id = 123;

external_knowledge:
- 'counties' refers to 'county entities';
- 'the fiscal year that has just passed' refers to fiscal year 2022;
- 'successfully concluded' implies that the transaction status is 'completed'.

- A significant amount is considered to be over 100,000;
- The term 'counties' refers to entities whose descriptions contain the word 'county';
- Debt retirement, interest, and short-term debt payments are part of operating expenditures.
